const W=Math.min(innerWidth,480),H=innerHeight;class S extends Phaser.Scene{create(){this.add.rectangle(W/2,H/2,W,H,0x1f2937);this.queue=[];this.score=0;this.ui=this.add.text(10,10,'Served:0');this.menu=['🍔','🌭','🍕'];this.order=this.add.text(W/2,80,'',{fontSize:'48px'}).setOrigin(.5);this.btns=this.menu.map((m,i)=>{const b=this.add.rectangle(90+i*140,H-70,100,44,0x059669).setInteractive();this.add.text(90+i*140,H-82,m,{fontSize:'28px'}).setOrigin(.5);b.on('pointerdown',()=>this.serve(m));return b;});this.time.addEvent({delay:1000,loop:true,callback:()=>this.newOrder()});this.r=this.input.keyboard.addKey('R');this.newOrder();}newOrder(){if(this.over)return;this.current=Phaser.Utils.Array.GetRandom(this.menu);this.order.setText(this.current);}serve(m){if(this.over)return;if(m===this.current){this.score++;this.ui.setText('Served:'+this.score);this.newOrder();if(this.score>=20){this.over=true;this.add.text(W/2,H/2,'CLEAR R').setOrigin(.5);}}else{this.score=Math.max(0,this.score-1);this.ui.setText('Served:'+this.score);}}update(){if(this.r.isDown)this.scene.restart();}}
new Phaser.Game({type:Phaser.AUTO,parent:'game',width:W,height:H,scene:[S]});
